const response = $input.first().json;

if (!response.response) {
  throw new Error('Invalid Ollama response');
}

const content = response.response;

// Try to parse JSON from response
let gameStructure;
try {
  gameStructure = JSON.parse(content);
} catch (e) {
  // Try to extract JSON from markdown code blocks
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/);
  if (jsonMatch) {
    gameStructure = JSON.parse(jsonMatch[1]);
  } else {
    // Try to find JSON object directly
    const jsonStart = content.indexOf('{');
    const jsonEnd = content.lastIndexOf('}');
    if (jsonStart !== -1 && jsonEnd !== -1) {
      const jsonStr = content.substring(jsonStart, jsonEnd + 1);
      gameStructure = JSON.parse(jsonStr);
    } else {
      throw new Error('Could not extract JSON from Ollama response');
    }
  }
}

return {
  game_structure: gameStructure,
  model: 'qwen2.5:32b (Ollama local)',
  timestamp: new Date().toISOString(),
  source: 'Ollama (localhost:11434)'
};
